const prog = $('Evalúa Caché').first().json;
const code = prog.original_code || '';
const lines = code.split('\n');

// Líneas de comentario (col 7 = '*' o '/')
const commentLines = lines.filter(l => l.length >= 7 && (l[6] === '*' || l[6] === '/')).length;
const codeLines = lines.length - commentLines;
const commentRatio = lines.length > 0 ? Math.round((commentLines / lines.length) * 100) : 0;

// GO TO
const gotoCount = (code.match(/\bGO\s*TO\b/gi) || []).length;
const gotoLines = [];
lines.forEach((l, i) => { if (/\bGO\s*TO\b/i.test(l)) gotoLines.push(i + 1); });

// PERFORM
const performCount = (code.match(/\bPERFORM\b/gi) || []).length;

// Párrafos en PROCEDURE DIVISION
const paragraphs = [];
let inProcedure = false;
lines.forEach((line, idx) => {
  if (/\bPROCEDURE\s+DIVISION\b/i.test(line)) { inProcedure = true; return; }
  if (!inProcedure) return;
  if (line.length >= 7 && (line[6] === '*' || line[6] === '/')) return;
  const m = line.match(/^[\s]{0,11}([A-Z][A-Z0-9-]*)\.[\s]*$/);
  if (m) paragraphs.push({ name: m[1].toUpperCase(), line: idx + 1 });
});

// Párrafos referenciados
const referenced = new Set();
lines.forEach(line => {
  const m = line.match(/\bPERFORM\s+([A-Z][A-Z0-9-]*)/gi);
  if (m) m.forEach(p => referenced.add(p.replace(/PERFORM\s+/i, '').trim().toUpperCase()));
});
const deadParagraphs = paragraphs
  .filter(p => !referenced.has(p.name))
  .map(p => `${p.name} (línea ${p.line})`);

// SQL
const execSqlCount = (code.match(/\bEXEC\s+SQL\b/gi) || []).length;

// Manejo de errores
const checksFileStatus = /FILE[\s-]STATUS/i.test(code);
const checksSqlCode   = /\bSQLCODE\b/i.test(code);

// EVALUATE (buen indicador de estructura)
const evaluateCount = (code.match(/\bEVALUATE\b/gi) || []).length;

return {
  json: {
    program_id:       prog.program_id,
    program_name:     prog.program_name,
    version_id:       prog.version_id,
    current_checksum: prog.current_checksum,
    original_code:    code,
    metrics: {
      total_lines:        lines.length,
      code_lines:         codeLines,
      comment_lines:      commentLines,
      comment_ratio:      commentRatio,
      goto_count:         gotoCount,
      goto_lines:         gotoLines,
      perform_count:      performCount,
      paragraph_count:    paragraphs.length,
      dead_paragraphs:    deadParagraphs,
      exec_sql_count:     execSqlCount,
      checks_file_status: checksFileStatus,
      checks_sqlcode:     checksSqlCode,
      evaluate_count:     evaluateCount
    }
  }
};

