const chainOut = $input.first().json;
const prog     = $('Computa Métricas COBOL').first().json;

// Limpia respuesta LLM
let raw = (chainOut.text || chainOut.output || '').trim();
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/```\s*$/i, '').trim();

let audit;
try {
  audit = JSON.parse(raw);
} catch(e) {
  throw new Error(`LLM no devolvió JSON válido: ${e.message}. Inicio respuesta: ${raw.substring(0, 300)}`);
}

const m = prog.metrics;

// Colores
const scoreColor = audit.overall_score >= 80 ? '#16a34a'
                 : audit.overall_score >= 60 ? '#d97706' : '#dc2626';
const sevColor   = { critical: '#dc2626', high: '#ea580c', medium: '#d97706', low: '#65a30d' };
const sevLabel   = { critical: 'Crítico', high: 'Alto', medium: 'Medio', low: 'Bajo' };

const findingsHtml = (audit.findings || []).map(f => `
  <div class="finding sev-${f.severity}">
    <span class="badge" style="background:${sevColor[f.severity] || '#6b7280'}">${sevLabel[f.severity] || f.severity}</span>
    <strong>${f.description}</strong>
    ${f.detail ? `<p class="detail">${f.detail}</p>` : ''}
  </div>`).join('');

const content_html = `<!DOCTYPE html>
<html lang="es">
<head><meta charset="UTF-8">
<style>
  body{font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;margin:0;padding:24px;background:#f9fafb;color:#111;}
  .header{display:flex;align-items:flex-start;gap:20px;margin-bottom:20px;}
  .score-circle{width:80px;height:80px;border-radius:50%;background:${scoreColor};color:#fff;display:flex;align-items:center;justify-content:center;font-size:28px;font-weight:bold;flex-shrink:0;}
  .program-info h1{margin:0 0 4px;font-size:20px;}
  .program-info .meta{color:#6b7280;font-size:13px;}
  .program-info .summary{margin-top:8px;font-size:14px;line-height:1.5;}
  .metrics-grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(150px,1fr));gap:10px;margin-bottom:20px;}
  .mc{background:#fff;border-radius:8px;padding:12px;box-shadow:0 1px 3px rgba(0,0,0,.08);}
  .mc .val{font-size:24px;font-weight:700;}
  .mc .lbl{font-size:11px;color:#6b7280;margin-top:2px;}
  .mc.warn .val{color:#dc2626;}
  .mc.ok   .val{color:#16a34a;}
  section{background:#fff;border-radius:8px;padding:16px;margin-bottom:14px;box-shadow:0 1px 3px rgba(0,0,0,.08);}
  section h2{margin:0 0 12px;font-size:15px;border-bottom:1px solid #e5e7eb;padding-bottom:8px;}
  .finding{border-left:3px solid #e5e7eb;padding:8px 12px;margin-bottom:8px;}
  .finding .detail{margin:4px 0 0;font-size:12px;color:#6b7280;font-family:monospace;background:#f3f4f6;padding:4px 8px;border-radius:4px;}
  .badge{display:inline-block;padding:2px 8px;border-radius:4px;color:#fff;font-size:11px;font-weight:600;margin-right:8px;}
  ul{margin:0;padding-left:20px;}li{margin-bottom:6px;font-size:14px;}
  .tag{display:inline-block;background:#e0f2fe;color:#0369a1;padding:1px 6px;border-radius:3px;font-size:11px;margin-right:4px;}
</style>
</head>
<body>
<div class="header">
  <div class="score-circle">${audit.overall_score}</div>
  <div class="program-info">
    <h1>${prog.program_name}</h1>
    <p class="meta">Complejidad: ${audit.complexity || '-'} &nbsp;|&nbsp; Generado: ${new Date().toLocaleDateString('es-AR')}</p>
    <p class="summary">${audit.summary || ''}</p>
  </div>
</div>

<div class="metrics-grid">
  <div class="mc"><div class="val">${m.total_lines}</div><div class="lbl">Líneas totales</div></div>
  <div class="mc"><div class="val">${m.comment_ratio}%</div><div class="lbl">Comentarios</div></div>
  <div class="mc ${m.goto_count > 0 ? 'warn' : 'ok'}"><div class="val">${m.goto_count}</div><div class="lbl">GO TO</div></div>
  <div class="mc"><div class="val">${m.paragraph_count}</div><div class="lbl">Párrafos</div></div>
  <div class="mc ${m.dead_paragraphs.length > 0 ? 'warn' : 'ok'}"><div class="val">${m.dead_paragraphs.length}</div><div class="lbl">Dead code</div></div>
  <div class="mc"><div class="val">${m.exec_sql_count}</div><div class="lbl">EXEC SQL</div></div>
  <div class="mc ${m.checks_file_status ? 'ok' : 'warn'}"><div class="val">${m.checks_file_status ? '✓' : '✗'}</div><div class="lbl">FILE STATUS</div></div>
  <div class="mc ${m.checks_sqlcode ? 'ok' : (m.exec_sql_count > 0 ? 'warn' : '')}"><div class="val">${m.checks_sqlcode ? '✓' : '✗'}</div><div class="lbl">SQLCODE</div></div>
</div>

${audit.findings && audit.findings.length > 0 ? `
<section>
  <h2>Hallazgos (${audit.findings.length})</h2>
  ${findingsHtml}
</section>` : ''}

${audit.strengths && audit.strengths.length > 0 ? `
<section>
  <h2>Fortalezas</h2>
  <ul>${(audit.strengths).map(s => `<li>${s}</li>`).join('')}</ul>
</section>` : ''}

${audit.recommendations && audit.recommendations.length > 0 ? `
<section>
  <h2>Recomendaciones</h2>
  <ul>${(audit.recommendations).map(r => `<li>${r}</li>`).join('')}</ul>
</section>` : ''}

</body></html>`;

return {
  json: {
    program_id:       prog.program_id,
    program_name:     prog.program_name,
    version_id:       prog.version_id,
    current_checksum: prog.current_checksum,
    overall_score:    audit.overall_score,
    findings_json:    JSON.stringify(audit),
    metrics_json:     JSON.stringify(m),
    content_html
  }
};

const parsed = $('Parsea y Genera HTML').first().json;
const audit   = JSON.parse(parsed.findings_json);

return {
  json: {
    success:      true,
    from_cache:   false,
    program_name: parsed.program_name,
    overall_score:parsed.overall_score,
    audit,
    metrics:      JSON.parse(parsed.metrics_json),
    content_html: parsed.content_html,
    generated_at: new Date().toISOString()
  }
};
